class Solution {
public:
    int bestClosingTime(string customers) {
        int n = customers.size();
        int totalY = 0;
        for (char c : customers) if (c == 'Y') ++totalY;

        int minPenalty = totalY;
        int bestJ = 0;
        int prefixN = 0;

        for (int j = 0; j < n; ++j) {
            if (customers[j] == 'N') ++prefixN;
            int penalty = prefixN + (totalY - (j + 1 - prefixN));
            if (penalty < minPenalty) {
                minPenalty = penalty;
                bestJ = j + 1;
            }
        }

        return bestJ;
    }
};
```
